#include <iostream>
#include <string>
#include <sstream>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N, K;
    cin >> N >> K;

    string current_line;
    for (int i = 0; i < N; i++) {
        string word;
        cin >> word;

        if (current_line.empty()) {
            current_line = word;
        } else if ((int)current_line.size() + 1 + (int)word.size() <= K) {
            current_line += " " + word;
        } else {
            cout << current_line << "\n";
            current_line = word;
        }
    }
    if (!current_line.empty()) {
        cout << current_line << "\n";
    }

    return 0;
}
